// src/pages/RegisterManageSub1Page.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import * as XLSX from 'xlsx'; // Import thư viện xlsx để xuất Excel

import './RegisterManageSub1Page.css'; // Import file CSS riêng cho trang này

/**
 * Component FarmListPage displays a list of facilities,
 * allowing searching, filtering, showing/hiding columns, and pagination.
 */
function FarmListPage() {
  // State to store the list of facilities fetched from the API
  const [farms, setFarms] = useState([]);
  // State for general search filter (by name, address, representative, etc.)
  const [filter, setFilter] = useState('');
  // State for Province filter
  const [selectedProvince, setSelectedProvince] = useState('');
  // State for Commune filter
  const [selectedCommune, setSelectedCommune] = useState('');
  // State for Species filter (retained as there might be nested species fields)
  const [selectedSpecies, setSelectedSpecies] = useState('');
  // State for Registration Type filter (Breeding Facility / Wood Business & Processing Facility)
  // Set default value to "Đăng ký cơ sở kinh doanh, chế biến gỗ" and hide the select element
  const [selectedLoaiCoSoDangKy, setSelectedLoaiCoSoDangKy] = useState('Đăng ký cơ sở kinh doanh, chế biến gỗ');
  // State for Wood Business Industry filter
  const [selectedNganhNgheKinhDoanhGo, setSelectedNganhNgheKinhDoanhGo] = useState('');
  // State for Status filter
  const [selectedTrangThai, setSelectedTrangThai] = useState(''); // Add state for Status filter

  // State to store unique Province values for the dropdown
  const [uniqueProvinces, setUniqueProvinces] = useState([]);
  // State to store unique Commune values for the dropdown
  const [uniqueCommunes, setUniqueCommunes] = useState([]);
  // State to store unique Species values for the dropdown
  const [uniqueSpecies, setUniqueSpecies] = useState([]);
  // State to store unique Registration Type values for the dropdown
  const [uniqueLoaiCoSoDangKy, setUniqueLoaiCoSoDangKy] = useState([]);
  // State to store unique Wood Business Industry values for the dropdown
  const [uniqueNganhNgheKinhDoanhGo, setUniqueNganhNgheKinhDoanhGo] = useState([]);
  // State to store unique Status values for the dropdown
  const [uniqueTrangThai, setUniqueTrangThai] = useState([]); // Add state for unique Status

  // Hook for page navigation
  const navigate = useNavigate();
  // Get authentication token from localStorage
  const token = localStorage.getItem('token');

  // Define table column configuration, including ID, display label, initial visibility, and minimum width
  const initialColumnsConfig = {
    // Facility Information
	tinhThanhPho: { id: 'tinhThanhPho', label: 'Tỉnh (TP)', visible: true, minWidth: '100px' },
	xaPhuong: { id: 'xaPhuong', label: 'Xã (Phường)', visible: true, minWidth: '100px' },
    diaChiCoSo: { id: 'diaChiCoSo', label: 'Địa chỉ cơ sở', visible: true, minWidth: '220px' },
    tenCoSo: { id: 'tenCoSo', label: 'Tên cơ sở', visible: true, minWidth: '180px' },

    vido: { id: 'vido', label: 'Vĩ độ', visible: true, minWidth: '80px' },
    kinhdo: { id: 'kinhdo', label: 'Kinh độ', visible: true, minWidth: '80px' },
    // loaiHinhCoSo: { id: 'loaiHinhCoSo', label: 'Loại hình cơ sở', visible: true, minWidth: '120px' }, // Removed
    ngayThanhLap: { id: 'ngayThanhLap', label: 'Ngày thành lập', visible: true, minWidth: '100px' },
    giayPhepKinhDoanh: { id: 'giayPhepKinhDoanh', label: 'Số GPKD', visible: true, minWidth: '100px' },

    // Representative Information
    tenNguoiDaiDien: { id: 'tenNguoiDaiDien', label: 'Người đại diện', visible: true, minWidth: '150px' },
    namSinh: { id: 'namSinh', label: 'Năm sinh', visible: true, minWidth: '80px' },
    soCCCD: { id: 'soCCCD', label: 'Số CCCD/Hộ chiếu', visible: true, minWidth: '120px' },
    ngayCapCCCD: { id: 'ngayCapCCCD', label: 'Ngày cấp CCCD', visible: true, minWidth: '100px' },
    noiCapCCCD: { id: 'noiCapCCCD', label: 'Nơi cấp CCCD', visible: true, minWidth: '120px' },
    soDienThoaiNguoiDaiDien: { id: 'soDienThoaiNguoiDaiDien', label: 'SĐT Người đại diện', visible: true, minWidth: '120px' },
    diaChiNguoiDaiDien: { id: 'diaChiNguoiDaiDien', label: 'Địa chỉ Người đại diện', visible: true, minWidth: '180px' },
    // emailNguoiDaiDien: { id: 'emailNguoiDaiDien', label: 'Email Người đại diện', visible: true, minWidth: '180px' }, // Removed

    // Breeding Facility
    mucDichNuoi: { id: 'mucDichNuoi', label: 'Mục đích nuôi', visible: false, minWidth: '120px' },
    hinhThucNuoi: { id: 'hinhThucNuoi', label: 'Hình thức nuôi', visible: false, minWidth: '120px' },
    maSoCoSoGayNuoi: { id: 'maSoCoSoGayNuoi', label: 'Mã số CS gây nuôi', visible: false, minWidth: '120px' },
    tongDan: { id: 'tongDan', label: 'Tổng đàn', visible: true, minWidth: '80px' },

    // Wood Business & Processing Facility
    loaiHinhKinhDoanhGo: { id: 'loaiHinhKinhDoanhGo', label: 'Loại hình KD gỗ', visible: false, minWidth: '120px' },
    nganhNgheKinhDoanhGo: { id: 'nganhNgheKinhDoanhGo', label: 'Ngành nghề KD gỗ', visible: false, minWidth: '120px' },
    khoiLuong: { id: 'khoiLuong', label: 'Khối lượng', visible: true, minWidth: '80px' },
    tenLamSan: { id: 'tenLamSan', label: 'Tên lâm sản', visible: true, minWidth: '150px' },
    tenKhoaHoc: { id: 'tenKhoaHoc', label: 'Tên khoa học', visible: true, minWidth: '180px' },

    // Other general fields
    trangThai: { id: 'trangThai', label: 'Trạng thái', visible: true, minWidth: '100px' },
    loaiCoSoDangKy: { id: 'loaiCoSoDangKy', label: 'Loại CS Đăng ký', visible: true, minWidth: '180px' },
    ghiChu: { id: 'ghiChu', label: 'Ghi chú', visible: false, minWidth: '200px' },

    // Action column (fixed width)
    actions: { id: 'actions', label: '🛠️', visible: true, width: '175px', minWidth: '175px', maxWidth: '175px' },
  };

  // State to manage column visibility
  const [columns, setColumns] = useState(initialColumnsConfig);
  // State to manage visibility of column options table
  const [showColumnOptions, setShowColumnOptions] = useState(false);

  // Pagination related states
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15); // Default 15 items per page

  /**
   * useEffect to load column visibility state from localStorage when the component mounts.
   * This helps persist user preferences across visits.
   */
  useEffect(() => {
    try {
      const savedColumns = localStorage.getItem('tableColumnsVisibility');
      if (savedColumns) {
        const parsedSavedColumns = JSON.parse(savedColumns);
        // Merge saved configuration with initial configuration to handle new/deleted columns
        const mergedColumns = Object.keys(initialColumnsConfig).reduce((acc, key) => {
          const savedCol = parsedSavedColumns.find(sCol => sCol.id === key);
          // Merge saved visibility, but retain initial properties (like width, minWidth)
          acc[key] = savedCol ? { ...initialColumnsConfig[key], visible: savedCol.visible } : initialColumnsConfig[key];
          return acc;
        }, {});
        setColumns(mergedColumns);
      }
    } catch (error) {
      console.error("Error loading column visibility state from localStorage:", error);
      // If there's an error loading, fallback to initial column configuration
      setColumns(initialColumnsConfig);
    }
  }, []); // Empty dependency array ensures this useEffect runs only once on mount

  /**
   * useEffect to save column visibility state to localStorage whenever the 'columns' state changes.
   */
  useEffect(() => {
    try {
      // Only save id and visibility status to avoid storing unnecessary CSS properties
      const columnsToSave = Object.keys(columns).map(key => ({
        id: key,
        visible: columns[key].visible
      }));
      localStorage.setItem('tableColumnsVisibility', JSON.stringify(columnsToSave));
    } catch (error) {
      console.error("Error saving column visibility state to localStorage:", error);
    }
  }, [columns]); // Runs whenever the 'columns' state changes


  /**
   * useEffect to fetch the list of facilities from the API when the component mounts
   * or when `selectedLoaiCoSoDangKy` or `selectedTrangThai` filters change.
   */
  useEffect(() => {
    const fetchFarms = async () => {
      try {
        const params = {};
        // Add farmType filter to params if `selectedLoaiCoSoDangKy` is selected
        // This filter will always be applied due to the default state
        if (selectedLoaiCoSoDangKy !== '') {
          params.farmType = selectedLoaiCoSoDangKy;
        }
        // Add status filter to params if `selectedTrangThai` is selected
        if (selectedTrangThai !== '') {
          params.trangThai = selectedTrangThai;
        }

        // Send GET request to API to get the list of facilities
        const response = await axios.get('http://localhost:10000/api/farms', {
          headers: {
            Authorization: `Bearer ${token}` // Send authentication token in the header
          },
          params: params // Pass filter parameters to the backend
        });

        // Access the .docs property of response.data
        const fetchedFarms = response.data.docs || [];
        setFarms(fetchedFarms); // Update farms state with received data

        // Extract unique values for filters from the loaded data
        const provinces = [...new Set(fetchedFarms.map(f => f.tinhThanhPho).filter(Boolean))].sort();
        const communes = [...new Set(fetchedFarms.map(f => f.xaPhuong).filter(Boolean))].sort();
        // Assuming 'species' is a nested array of objects with a 'name' property
        const species = [...new Set(fetchedFarms.flatMap(f => f.species ? f.species.map(s => s.name) : []).filter(Boolean))].sort();
        const loaiCoSoDangKy = [...new Set(fetchedFarms.map(f => f.loaiCoSoDangKy).filter(Boolean))].sort();
        const nganhNgheKinhDoanhGo = [...new Set(fetchedFarms.map(f => f.nganhNgheKinhDoanhGo).filter(Boolean))].sort();
        const trangThai = [...new Set(fetchedFarms.map(f => f.trangThai).filter(Boolean))].sort(); // Get unique status values

        // Update states containing unique values
        setUniqueProvinces(provinces);
        setUniqueCommunes(communes);
        setUniqueSpecies(species);
        setUniqueLoaiCoSoDangKy(loaiCoSoDangKy);
        setUniqueNganhNgheKinhDoanhGo(nganhNgheKinhDoanhGo);
        setUniqueTrangThai(trangThai);

      } catch (error) {
        console.error('❌ Error fetching facility list:', error);
        // If error due to authentication (401) or unauthorized (403), redirect to login page
        if (error.response && (error.response.status === 401 || error.response.status === 403)) {
          navigate('/');
        }
        setFarms([]); // Ensure farms is an empty array on error
      }
    };

    // Only load data if token exists
    if (token) {
      fetchFarms();
    } else {
      navigate('/'); // Redirect if no token
    }
  }, [token, navigate, selectedLoaiCoSoDangKy, selectedTrangThai]); // Re-fetch when token, navigate, selectedLoaiCoSoDangKy or selectedTrangThai changes

  /**
   * Function to handle deleting a facility.
   * @param {string} id - ID of the facility to delete.
   */
  const handleDelete = async (id) => {
    // Replace window.confirm with a custom modal if you have one
    // if (window.confirm('Are you sure you want to delete?')) {
      try {
        // Send DELETE request to API to delete facility
        await axios.delete(`http://localhost:10000/api/farms/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        // Update the list of facilities by filtering out the deleted one
        setFarms(farms.filter(f => f._id !== id));
      } catch (error) {
        console.error('Error deleting:', error);
      }
    // }
  };

  /**
   * Function to handle editing facility information.
   * @param {string} id - ID of the facility to edit.
   */
  const handleEdit = (id) => {
    navigate(`/edit-farm/${id}`); // Redirect to edit page with facility ID
  };

  /**
   * Function to handle viewing facility details.
   * @param {string} id - ID of the facility to view details.
   */
  const handleView = (id) => {
    navigate(`/farm-details/${id}`); // Redirect to detail page with facility ID
  };

  /**
   * Filter the list of facilities based on all criteria (frontend filtering for other fields).
   */
  const filteredFarms = farms.filter(f => {
    // Check match with general search filter
    const generalMatch = (
      (f.tenCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.tinhThanhPho || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.xaPhuong || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.diaChiCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.ghiChu || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.loaiCoSoDangKy || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.nganhNgheKinhDoanhGo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.tongDan && String(f.tongDan).toLowerCase().includes(filter.toLowerCase())) ||
      (f.khoiLuong && String(f.khoiLuong).toLowerCase().includes(filter.toLowerCase())) ||
      (f.tenLamSan && String(f.tenLamSan).toLowerCase().includes(filter.toLowerCase())) ||
      (f.tenKhoaHoc && String(f.tenKhoaHoc).toLowerCase().includes(filter.toLowerCase())) ||
      (f.trangThai && String(f.trangThai).toLowerCase().includes(filter.toLowerCase())) ||
      (f.tenNguoiDaiDien || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.namSinh && String(f.namSinh).toLowerCase().includes(filter.toLowerCase())) ||
      (f.soCCCD && String(f.soCCCD).toLowerCase().includes(filter.toLowerCase())) ||
      (f.ngayCapCCCD && new Date(f.ngayCapCCCD).toLocaleDateString().toLowerCase().includes(filter.toLowerCase())) ||
      (f.noiCapCCCD && String(f.noiCapCCCD).toLowerCase().includes(filter.toLowerCase())) ||
      (f.soDienThoaiNguoiDaiDien && String(f.soDienThoaiNguoiDaiDien).toLowerCase().includes(filter.toLowerCase())) ||
      (f.diaChiNguoiDaiDien && String(f.diaChiNguoiDaiDien).toLowerCase().includes(filter.toLowerCase()))
      // Removed: || (f.loaiHinhCoSo || '').toLowerCase().includes(filter.toLowerCase())
      // Removed: || (f.emailNguoiDaiDien && String(f.emailNguoiDaiDien).toLowerCase().includes(filter.toLowerCase()))
    );

    // Check match with Province filter
    const provinceMatch = selectedProvince ? (f.tinhThanhPho === selectedProvince) : true;
    // Check match with Commune filter
    const communeMatch = selectedCommune ? (f.xaPhuong === selectedCommune) : true;
    // Check match with Species filter (if species field exists)
    const speciesMatch = selectedSpecies ? (f.species && f.species.some(s => s.name === selectedSpecies)) : true;
    // `nganhNgheKinhDoanhGoMatch` is currently handled by the backend filter, but kept for consistency if needed for other filters
    const nganhNgheKinhDoanhGoMatch = selectedNganhNgheKinhDoanhGo ? (f.nganhNgheKinhDoanhGo === selectedNganhNgheKinhDoanhGo) : true;
    // `trangThaiMatch` is currently handled by the backend filter, but kept for consistency if needed for other filters
    const trangThaiMatch = selectedTrangThai ? (f.trangThai === selectedTrangThai) : true;


    // Return true if all filter conditions match
    return generalMatch && provinceMatch && communeMatch && speciesMatch && nganhNgheKinhDoanhGoMatch && trangThaiMatch;
  });

  // Pagination logic
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = filteredFarms.slice(indexOfFirstItem, indexOfLastItem);

  const totalPages = Math.ceil(filteredFarms.length / itemsPerPage);

  // Function to change current page
  const paginate = (pageNumber) => setCurrentPage(pageNumber);

  // Function to go to next page
  const nextPage = () => {
    if (currentPage < totalPages) {
      setCurrentPage(currentPage + 1);
    }
  };

  // Function to go to previous page
  const prevPage = () => {
    if (currentPage > 1) {
      setCurrentPage(currentPage - 1);
    }
  };

  /**
   * Function to handle toggling column visibility.
   * @param {string} columnKey - Key of the column to change visibility.
   */
  const handleColumnToggle = (columnKey) => {
    setColumns(prevColumns => ({
      ...prevColumns,
      [columnKey]: {
        ...prevColumns[columnKey],
        visible: !prevColumns[columnKey].visible // Invert column visibility
      }
    }));
  };

  /**
   * Function to select all visible columns.
   */
  const handleSelectAllColumns = () => {
    setColumns(prevColumns => {
      const newColumns = { ...prevColumns };
      for (const key in newColumns) {
        newColumns[key].visible = true;
      }
      return newColumns;
    });
  };

  /**
   * Function to deselect all visible columns (except action column).
   */
  const handleDeselectAllColumns = () => {
    setColumns(prevColumns => {
      const newColumns = { ...prevColumns };
      for (const key in newColumns) {
        // Always keep 'actions' column visible
        if (key === 'actions') {
          newColumns[key].visible = true;
        } else {
          newColumns[key].visible = false;
        }
      }
      return newColumns;
    });
  };

  /**
   * Function to export table data to an Excel file.
   */
  const handleExportExcel = () => {
    // Filter out visible columns that are not 'actions' column
    const columnsToExport = Object.values(columns).filter(col => col.visible && col.id !== 'actions');

    // Prepare data for Excel
    const dataToExport = filteredFarms.map(farm => {
      const rowData = {};
      columnsToExport.forEach(col => {
        let value = farm[col.id];
        // Handle date formatting for date fields
        if (['ngayThanhLap', 'ngayCapCCCD'].includes(col.id)) { // Only these two date fields are in Farm.js schema
          value = value ? new Date(value).toLocaleDateString() : '';
        }
        rowData[col.label] = value; // Use label as column header in Excel
      });
      return rowData;
    });

    // Create worksheet from JSON
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    // Create new workbook
    const wb = XLSX.utils.book_new();
    // Add worksheet to workbook
    XLSX.utils.book_append_sheet(wb, ws, "DanhSachCoSo");
    // Export Excel file
    XLSX.writeFile(wb, "DanhSachCoSo.xlsx");
  };

  return (
    <div className="farm-list-container"> {/* Main container for the list page */}
      <h2>📋 Danh sách cơ sở kinh doanh, chế biến gỗ</h2>

      <div className="filter-container"> {/* Container for filters */}
        <input
          type="text"
          placeholder="🔍 Tìm kiếm chung..."
          value={filter}
          onChange={e => setFilter(e.target.value)}
        />

        {/* Bộ lọc mới cho Loại cơ sở đăng ký - ẨN ĐI */}
        {/* <select
          value={selectedLoaiCoSoDangKy}
          onChange={e => setSelectedLoaiCoSoDangKy(e.target.value)}
        >
          <option value="">Tất cả cơ sở</option>
          <option value="Đăng ký cơ sở gây nuôi">Đăng ký cơ sở gây nuôi</option>
          <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Đăng ký cơ sở kinh doanh, chế biến gỗ</option>
        </select> */}

        <select
          value={selectedProvince}
          onChange={e => setSelectedProvince(e.target.value)}
        >
          <option value="">Tất cả Tỉnh (TP)</option>
          {uniqueProvinces.map(province => (
            <option key={province} value={province}>{province}</option>
          ))}
        </select>

        <select
          value={selectedCommune}
          onChange={e => setSelectedCommune(e.target.value)}
        >
          <option value="">Tất cả Xã (Phường)</option>
          {uniqueCommunes.map(commune => (
            <option key={commune} value={commune}>{commune}</option>
          ))}
        </select>

        <select
          value={selectedSpecies}
          onChange={e => setSelectedSpecies(e.target.value)}
        >
          <option value="">Tất cả Loài nuôi</option>
          {uniqueSpecies.map(species => (
            <option key={species} value={species}>{species}</option>
          ))}
        </select>

        {/* New filter for Wood Business Industry */}
        <select
          value={selectedNganhNgheKinhDoanhGo}
          onChange={e => setSelectedNganhNgheKinhDoanhGo(e.target.value)}
        >
          <option value="">Tất cả Ngành nghề KD gỗ</option>
          {uniqueNganhNgheKinhDoanhGo.map(nganhNghe => (
            <option key={nganhNghe} value={nganhNghe}>{nganhNghe}</option>
          ))}
        </select>

        {/* New filter for Status */}
        <select
          value={selectedTrangThai}
          onChange={e => setSelectedTrangThai(e.target.value)}
        >
          <option value="">Tất cả Trạng thái</option>
          {uniqueTrangThai.map(status => (
            <option key={status} value={status}>{status}</option>
          ))}
        </select>

        <button
          onClick={() => setShowColumnOptions(!showColumnOptions)}
        >
          {showColumnOptions ? 'Ẩn cột' : 'Hiện, ẩn cột'}
        </button>

        {/* Export Excel button */}
        <button
          onClick={handleExportExcel}
          className="export-excel-button"
        >
          Xuất Excel
        </button>
      </div>

      {showColumnOptions && (
        <div className="column-options-container">
          <h3>Chọn cột hiển thị:</h3>
          <div className="column-options-grid">
            {Object.keys(columns).map(key => (
              <label key={key}>
                <input
                  type="checkbox"
                  checked={columns[key].visible}
                  onChange={() => handleColumnToggle(key)}
                />
                {columns[key].label}
              </label>
            ))}
          </div>
          <div className="column-control-buttons"> {/* Add container for control buttons */}
            <button onClick={handleSelectAllColumns} className="select-all-columns-button">
              Chọn tất cả
            </button>
            <button onClick={handleDeselectAllColumns} className="select-all-columns-button">
              Bỏ chọn tất cả
            </button>
          </div>
        </div>
      )}

      {/* Display message when no facilities are registered */}
      {farms.length === 0 && !filter && <p>Không có cơ sở nuôi nào được đăng ký.</p>}
      {farms.length === 0 && filter && <p>Không tìm thấy cơ sở nuôi nào phù hợp với bộ lọc.</p>}

      {/* Table to display the list of facilities if there is data */}
      {filteredFarms.length > 0 && (
        <table border="1" cellPadding="8" className="table-auto w-full border-collapse">
          <thead style={{ background: '#f0f0f0' }}>
            <tr>
              {Object.keys(columns).map(key => (
                <th
                  key={key}
                  className={!columns[key].visible ? 'column-hidden' : ''}
                  style={
                    key === 'actions'
                      ? { // Action column: fixed width
                          width: columns[key].width,
                          minWidth: columns[key].minWidth,
                          maxWidth: columns[key].maxWidth,
                        }
                      : (columns[key].visible
                          ? { // Non-action columns that are visible: use minWidth as width
                              width: columns[key].minWidth, // Set width to minWidth
                              minWidth: columns[key].minWidth, // Ensure minWidth is respected
                              maxWidth: columns[key].maxWidth || 'auto', // Allow expansion if space permits, but retain ellipsis
                            }
                          : {}
                        )
                  }
                >
                  {columns[key].label}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {currentItems.map((f, i) => (
              <tr key={f._id || i}>
                {Object.keys(columns).map(key => (
                  <td
                    key={`${f._id || i}-${key}`}
                    className={!columns[key].visible ? 'column-hidden' : ''}
                    style={
                      key === 'actions'
                        ? { // Action column: fixed width
                            width: columns[key].width,
                            minWidth: columns[key].minWidth,
                            maxWidth: columns[key].maxWidth,
                          }
                        : (columns[key].visible
                            ? { // Non-action columns that are visible: use minWidth as width
                                width: columns[key].minWidth, // Set width to minWidth
                                minWidth: columns[key].minWidth, // Ensure minWidth is respected
                                maxWidth: columns[key].maxWidth || 'auto', // Allow expansion if space permits, but retain ellipsis
                              }
                            : {}
                          )
                    }
                  >
                    {/* Handle date formatting for date fields */}
                    {['ngayThanhLap', 'ngayCapCCCD'].includes(key) ?
                      (f[key] ? new Date(f[key]).toLocaleDateString() : '') :
                      (key === 'actions' ? (
                        <div className="action-buttons-cell">
                          <button onClick={() => handleView(f._id)} className="action-button view-button">Sổ nuôi</button>{' '}
                          <button onClick={() => handleEdit(f._id)} className="action-button edit-button">✏️</button>{' '}
                          <button onClick={() => handleDelete(f._id)} className="action-button delete-button">🗑️</button>
                        </div>
                      ) : f[key])
                    }
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* Pagination controls */}
      {filteredFarms.length > 0 && (
        <div className="pagination-container">
          <div className="pagination-info">
            {indexOfFirstItem + 1} - {Math.min(indexOfLastItem, filteredFarms.length)} / {filteredFarms.length} bản ghi
          </div>
          <div className="pagination-controls">
            <button onClick={prevPage} disabled={currentPage === 1} className="pagination-button">«</button>
            {Array.from({ length: totalPages }, (_, i) => (
              <button
                key={i + 1}
                onClick={() => paginate(i + 1)}
                className={`pagination-button ${currentPage === i + 1 ? 'active' : ''}`}
              >
                {i + 1}
              </button>
            ))}
            <button onClick={nextPage} disabled={currentPage === totalPages} className="pagination-button">»</button>
          </div>
          <div className="items-per-page">
            <select value={itemsPerPage} onChange={(e) => {
              setItemsPerPage(Number(e.target.value));
              setCurrentPage(1); // Reset to the first page when items per page changes
            }}>
              <option value="5">5 bản ghi/trang</option>
              <option value="10">10 bản ghi/trang</option>
              <option value="15">15 bản ghi/trang</option>
              <option value="20">20 bản ghi/trang</option>
              <option value="50">50 bản ghi/trang</option>
            </select>
          </div>
        </div>
      )}
    </div>
  );
}

export default FarmListPage;
